export const frequencyToCommitmentSchedule = (frequency?: string | null) => {
  switch (frequency) {
    case 'weekly': {
      return {
        every: 'week',
        interval: 1,
      };
    }

    case 'biweekly': {
      return {
        every: 'week',
        interval: 2,
      };
    }

    case 'monthly': {
      return {
        every: 'month',
        interval: 1,
      };
    }

    case 'quarterly': {
      return {
        every: 'month',
        interval: 3,
      };
    }

    case 'semiannually': {
      return {
        every: 'month',
        interval: 6,
      };
    }

    case 'yearly': {
      return {
        every: 'year',
        interval: 1,
      };
    }

    default:
      return null;
  }
};

